package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.ObjectConstructor;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

import java.lang.reflect.Type;
import java.util.HashMap;
import java.util.Map;

class MapTypeAdapterFactoryTest {

  @Mock Gson gson;
  @Mock ConstructorConstructor constructorConstructor;
  @Mock ObjectConstructor<Object> objectConstructor;

  MapTypeAdapterFactory factory;

  @BeforeEach
  void setUp() {
    MockitoAnnotations.openMocks(this);
    factory = new MapTypeAdapterFactory(constructorConstructor, true);
  }

  @Test
  void create_whenTypeIsNotMap_returnsNull() {
    TypeToken<String> typeToken = TypeToken.get(String.class);

    TypeAdapter<String> adapter = factory.create(gson, typeToken);

    assertNull(adapter);
  }

  @Test
  void create_whenTypeIsMap_returnsAdapter() {
    TypeToken<Map<String, Integer>> typeToken = new TypeToken<Map<String, Integer>>() {};
    Type keyType = String.class;
    Type valueType = Integer.class;

    // Mock $Gson$Types.getMapKeyAndValueTypes to return key and value types.
    // Since it's a static method, we cannot mock easily, so we rely on real behavior.
    // The real method returns the correct key and value types for Map<String, Integer>.

    // Mock gson.getAdapter for value type
    TypeAdapter<Integer> valueAdapter = mock(TypeAdapter.class);
    when(gson.getAdapter(TypeToken.get(valueType))).thenReturn(valueAdapter);

    // Mock getKeyAdapter method via spy to return a dummy keyAdapter
    MapTypeAdapterFactory spyFactory = spy(factory);
    TypeAdapter<String> keyAdapter = mock(TypeAdapter.class);
    doReturn(keyAdapter).when(spyFactory).getKeyAdapter(gson, keyType);

    // Mock constructorConstructor.get to return objectConstructor
    when(constructorConstructor.get(typeToken)).thenReturn((ObjectConstructor) objectConstructor);

    // Call create
    TypeAdapter<Map<String, Integer>> adapter = spyFactory.create(gson, typeToken);

    assertNotNull(adapter);
    // The returned adapter should be an instance of MapTypeAdapterFactory.Adapter
    assertEquals("com.google.gson.internal.bind.MapTypeAdapterFactory$Adapter", adapter.getClass().getName());
  }

}
